import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------- Quote: empty + base premiums + processing fee ----------
  it.todo("empty item list -> premium 5 G (only processing fee)");
  it.todo("single sword (plain) -> 105 G (100 base + 5 fee)");
  it.todo("single amulet (plain) -> 65 G (60 base + 5 fee)");
  it.todo("single staff (plain) -> 85 G (80 base + 5 fee)");
  it.todo("single potion (plain) -> 45 G (40 base + 5 fee)");

  // ---------- Components & building block of 3 alike ----------
  it.todo("2 runes -> 55 G premium (50 base + 5 fee)");
  it.todo("3 runes -> 65 G premium (60 base block + 5 fee)");
  it.todo("4 runes -> 105 G premium (100 base, no block + 5 fee)");
  it.todo("7 runes -> 180 G premium (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone -> 80 G premium (75 base + 5 fee, no block)");
  it.todo("3 runes + 3 moonstones -> 125 G premium (120 base two blocks + 5 fee)");

  // ---------- Item-specific modifiers: cursed, high enchantment ----------
  it.todo("cursed sword (enchant 3) -> 155 G (100 + 50 curse + 5 fee)");
  it.todo("sword with enchant 5 -> 135 G (100 + 30 high-ench + 5 fee)");
  it.todo("sword with enchant 4 -> 105 G (no high-ench surcharge)");
  it.todo("cursed sword with enchant 5 -> 185 G (100 + 50 + 30 + 5)");

  // ---------- Policy-wide modifiers: loyalty, first insurance, follow-up ----------
  it.todo("plain sword for customer with 2 years -> 90 G (100 - 20 loyalty + 5+5? actually 100*0.8=80, +5 fee = 85)");
  it.todo("plain sword for first insurance (yearsWithMHPCO 0) -> 115 G (100 + 10 first + 5 fee)");
  it.todo("plain sword on second contract -> 90 G (100 - 15 follow-up + 5 fee)");

  // ---------- Integration examples from spec ----------
  it.todo("newcomer with cursed sword (enchant 3) -> 165 G");
  it.todo("long-standing customer's second contract, cursed sword enchant 7 -> 160 G");

  // ---------- Multi-item modifier scope ----------
  it.todo("cursed sword + plain amulet (newcomer first contract) -> sums correctly with item-specific curse on sword only");

  // ---------- Rounding in MHPCO's favor (premium) ----------
  it.todo("premium yielding 197.5 G -> 198 G (rounded up)");

  // ---------- Claim: standard reimbursement ----------
  it.todo("regular sword enchant 3, damage 500 -> payout 400 (500-100 deductible)");
  it.todo("rune insured, damage 200 -> payout 100 (no special clauses)");

  // ---------- Claim: high-enchantment 50% ----------
  it.todo("steel sword enchant 9, damage 1000 -> payout 400 (500 - 100)");

  // ---------- Claim: dragon-material full reimbursement ----------
  it.todo("dragon sword enchant 5, damage 800 -> payout 700 (800 - 100)");

  // ---------- Claim: combined dragon + high-enchant (50% wins) ----------
  it.todo("dragon sword enchant 9, damage 1000 -> payout 400 (500 - 100)");
  it.todo("dragon sword enchant exactly 8, damage 1000 -> payout 400");

  // ---------- Claim: deductible per damage event (multiple items) ----------
  it.todo("dragon attack damages sword 500 + amulet 300 -> payout 600 (each item -100)");

  // ---------- Claim: cap exhaustion ----------
  it.todo("sword insured (cap 2000), two successive 1500 claims -> 1400 then 600, remainingCap 0");

  // ---------- Multiple items of same type ----------
  it.todo("policy with two swords, both damaged 500 each -> payout 800 (each -100)");
  it.todo("more damage entries of a type than policy covers -> CLI exits non-zero");

  // ---------- Rounding payout (down) ----------
  it.todo("payout calculation yielding 350.5 -> 350 (rounded down)");

  // ---------- Error cases ----------
  it.todo("unknown item type in quote -> CLI exits non-zero, error to stderr");
  it.todo("claim references item not in policy -> CLI exits non-zero");
  it.todo("claim with negative damage amount -> CLI exits non-zero");

  // ---------- CLI integration ----------
  it.todo("schema example: amulet quote + claim returns premium and payout+remainingCap");
});

