const PROCESSING_FEE = 5;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const basePremium = step.items.reduce((sum, item) => {
      if (item.type === "sword") return sum + 100;
      return sum;
    }, 0);
    return { premium: basePremium + PROCESSING_FEE };
  });
  return { results };
};

