const PROCESSING_FEE = 5;
const SWORD_BASE_PRICE = 100;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const basePriceFor = (item: Item): number => {
  if (item.type === "sword") return SWORD_BASE_PRICE;
  return 0;
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  const basePremium = step.items.reduce(
    (sum, item) => sum + basePriceFor(item),
    0,
  );
  return { premium: basePremium + PROCESSING_FEE };
};

