const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const BASE_PRICE_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };
type ScenarioResult = { results: QuoteResult[] };

const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type] ?? 0;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const totalBasePriceFor = (items: Item[]): number => {
  const counts = countByType(items);
  let total = 0;
  for (const [type, count] of counts) {
    if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PRICE;
    } else {
      total += count * (BASE_PRICE_BY_TYPE[type] ?? 0);
    }
  }
  return total;
};

