const itemPremium = (item: Item): number => {
  const base = basePriceFor(item.type);
  const curse = item.cursed ? base * 0.5 : 0;
  return base + curse;
};

const totalBasePriceFor = (items: Item[]): number => {
  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const mainTotal = mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
  const componentTotal = Array.from(countByType(components)).reduce(
    (total, [type, count]) => total + priceForGroup(type, count),
    0,
  );
  return mainTotal + componentTotal;
};

