// Policy base sum = sum of item base premiums (block-aware for components,
// without item-specific modifiers like curse or high-enchantment).
const policyBaseSum = (items: Item[]): number => {
  const mainBase = items
    .filter((i) => !isComponent(i))
    .reduce((sum, item) => sum + basePriceFor(item.type), 0);
  const componentBase = componentsSubtotal(items.filter(isComponent));
  return mainBase + componentBase;
};

