const followUpDiscountFor = (isFollowUp: boolean, baseSum: number): number =>
  isFollowUp ? baseSum * FOLLOW_UP_DISCOUNT_RATE : 0;

const quoteItems = (
  items: Item[],
  customer: Customer,
  isFollowUp: boolean,
): QuoteResult => {
  const baseSum = policyBaseSum(items);
  const subtotal = itemsSubtotal(items);
  const firstInsurance = firstInsuranceSurchargeFor(baseSum);
  const loyalty = loyaltyDiscountFor(customer, baseSum);
  const followUp = followUpDiscountFor(isFollowUp, baseSum);
  return {
    premium: subtotal + firstInsurance - loyalty - followUp + PROCESSING_FEE,
  };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    const isFollowUp = quoteCount > 0;
    quoteCount += 1;
    return quoteItems(step.items, scenario.customer, isFollowUp);
  });
  return { results };
};

