const insuranceValueFor = (type: string): number =>
  INSURANCE_VALUE_BY_TYPE[type] ?? 0;

const insuranceSumFor = (items: Item[]): number =>
  sumBy(items, (item) => insuranceValueFor(item.type));

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const processClaim = (
  step: ClaimStep,
  policies: Map<number, Policy>,
): ClaimResult => {
  const policy = policies.get(step.policy)!;
  const rawPayout = sumBy(step.incident.damages, payoutForDamage);
  const payout = Math.min(rawPayout, policy.cap);
  policy.cap -= payout;
  return { payout, remainingCap: policy.cap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies = new Map<number, Policy>();
  let quoteCount = 0;
  const results = scenario.steps.map((step, index): StepResult => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies.set(index, {
        items: step.items,
        cap: insuranceSumFor(step.items) * CAP_MULTIPLIER,
      });
      return quoteItems(step.items, scenario.customer, isFollowUp);
    }
    return processClaim(step, policies);
  });
  return { results };
};

