const reimbursableAmount = (damage: Damage, item: Item): number => {
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
    return damage.amount * HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE;
  }
  return damage.amount;
};

const payoutForDamage = (damage: Damage, item: Item): number =>
  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE);

const findItem = (items: Item[], type: string): Item | undefined =>
  items.find((item) => item.type === type);

const processClaim = (
  step: ClaimStep,
  ledger: ClaimLedger,
): ClaimResult => {
  const policy = ledger.policies.get(step.policy)!;
  const availableCap = remainingCapFor(ledger, step.policy);
  const rawPayout = sumBy(step.incident.damages, (damage) => {
    const item = findItem(policy.items, damage.itemType)!;
    return payoutForDamage(damage, item);
  });
  const payout = Math.min(rawPayout, availableCap);
  recordPayout(ledger, step.policy, payout);
  return { payout, remainingCap: availableCap - payout };
};

